let brief;
try { brief = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); } catch { brief = {}; }
return [{ json: { generated_at: new Date().toISOString(), meeting_date: $env.BOARD_MEETING_DATE || 'upcoming', ...brief } }];

